<script setup>import{ref,onMounted,onUnmounted}from'vue';const p=defineProps(['label','side','align','sideOffset','alignOffset','open','closeOnOutside','closeOnEscape']);const shown=ref(!!p.open),root=ref(),trigger=ref(),id='popover-'+p.label.toLowerCase().replace(/\W/g,'-');const outside=e=>{if(p.closeOnOutside!==false&&!root.value.contains(e.target))shown.value=false},key=e=>{if(e.key==='Escape'&&p.closeOnEscape!==false){shown.value=false;trigger.value.focus()}};onMounted(()=>{document.addEventListener('pointerdown',outside);document.addEventListener('keydown',key)});onUnmounted(()=>{document.removeEventListener('pointerdown',outside);document.removeEventListener('keydown',key)})</script><template><section ref="root" class="popover-demo"><strong>{{p.label}}</strong><button ref="trigger" class="popover-trigger" aria-haspopup="dialog" :aria-expanded="shown" :aria-controls="id" @click="shown=!shown">Toggle</button><div v-if="shown" :id="id" role="dialog" :aria-label="p.label" :class="['kumo-popover','side-'+p.side,'align-'+p.align]" :style="{'--side-offset':(p.sideOffset??8)+'px','--align-offset':(p.alignOffset??0)+'px'}"><p>Popover content</p><button @click="shown=false">Close</button></div></section></template>